import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  HttpStatus,
} from '@nestjs/common';
import { Response } from 'express';

@Catch()
export class HttpExceptionFilter implements ExceptionFilter {
  catch(exception: unknown, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();

    let status = HttpStatus.INTERNAL_SERVER_ERROR;
    let message = 'Internal server error';
    let errors: any = null;

    if (exception instanceof HttpException) {
      status = exception.getStatus();
      const exceptionResponse = exception.getResponse();

      if (typeof exceptionResponse === 'string') {
        message = exceptionResponse;
      } else if (typeof exceptionResponse === 'object') {
        const res = exceptionResponse as any;
        message = res.message || exception.message;
        errors = res.errors || null;
        if (Array.isArray(message)) {
          errors = message;
          message = 'Validation failed';
        }
      }
    }

    response.status(status).json({
      success: false,
      statusCode: status,
      message,
      errors,
      timestamp: new Date().toISOString(),
    });
  }
}

import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { ROLES_KEY } from '../decorators/roles.decorator';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const requiredRoles = this.reflector.getAllAndOverride<string[]>(
      ROLES_KEY,
      [context.getHandler(), context.getClass()],
    );
    if (!requiredRoles) {
      return true;
    }
    const { user } = context.switchToHttp().getRequest();
    return requiredRoles.some((role) => user?.role === role);
  }
}

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
} from '@nestjs/common';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';

export interface ResponseFormat<T> {
  success: boolean;
  data: T;
  timestamp: string;
}

@Injectable()
export class TransformInterceptor<T> implements NestInterceptor<
  T,
  ResponseFormat<T>
> {
  intercept(
    context: ExecutionContext,
    next: CallHandler,
  ): Observable<ResponseFormat<T>> {
    return next.handle().pipe(
      map((data) => ({
        success: true,
        data,
        timestamp: new Date().toISOString(),
      })),
    );
  }
}

import { NestFactory } from '@nestjs/core';
import { ValidationPipe } from '@nestjs/common';
import { SwaggerModule, DocumentBuilder } from '@nestjs/swagger';
import { AppModule } from './app.module';
import { HttpExceptionFilter } from './common/filters/http-exception.filter';
import { TransformInterceptor } from './common/interceptors/transform.interceptor';
import { json, urlencoded } from 'express';

async function bootstrap() {
  const app = await NestFactory.create(AppModule);

  // Increase payload limit for base64 image uploads
  app.use(json({ limit: '50mb' }));
  app.use(urlencoded({ limit: '50mb', extended: true }));

  // Global prefix
  app.setGlobalPrefix('api');

  // CORS
  app.enableCors({
    origin: process.env.FRONTEND_URL || 'http://localhost:5173',
    credentials: true,
  });

  // Global pipes
  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: true,
      transform: true,
      transformOptions: { enableImplicitConversion: true },
    }),
  );

  // Global filters
  app.useGlobalFilters(new HttpExceptionFilter());

  // Global interceptors
  app.useGlobalInterceptors(new TransformInterceptor());

  // Swagger
  const config = new DocumentBuilder()
    .setTitle('Trường Thành Stationery API')
    .setDescription('API documentation for Trường Thành Stationery Store')
    .setVersion('1.0')
    .addBearerAuth()
    .addTag('auth', 'Authentication endpoints')
    .addTag('products', 'Product management')
    .addTag('categories', 'Category management')
    .addTag('orders', 'Order management')
    .addTag('inventory', 'Inventory management')
    .addTag('customers', 'Customer management')
    .addTag('promotions', 'Promotion management')
    .addTag('reports', 'Reports & analytics')
    .build();

  const document = SwaggerModule.createDocument(app, config);
  SwaggerModule.setup('api/docs', app, document);

  const port = process.env.PORT || 3000;
  await app.listen(port);
  console.log(`🚀 Server running on http://localhost:${port}`);
  console.log(`📚 Swagger docs at http://localhost:${port}/api/docs`);
}
bootstrap();

import {
  Controller,
  Post,
  Get,
  Body,
  UseGuards,
  Request,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { ApiBearerAuth, ApiTags, ApiOperation } from '@nestjs/swagger';
import { AuthService } from './auth.service';
import { RegisterDto, LoginDto } from './dto/auth.dto';

@ApiTags('auth')
@Controller('auth')
export class AuthController {
  constructor(private authService: AuthService) {}

  @Post('register')
  @ApiOperation({ summary: 'Register a new user' })
  async register(@Body() registerDto: RegisterDto) {
    return this.authService.register(registerDto);
  }

  @Post('login')
  @ApiOperation({ summary: 'Login with email and password' })
  async login(@Body() loginDto: LoginDto) {
    return this.authService.login(loginDto);
  }

  @Get('me')
  @UseGuards(AuthGuard('jwt'))
  @ApiBearerAuth()
  @ApiOperation({ summary: 'Get current user profile' })
  async getProfile(@Request() req: any) {
    return this.authService.getProfile(req.user._id);
  }
}

import { Injectable, UnauthorizedException } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { ExtractJwt, Strategy } from 'passport-jwt';
import { ConfigService } from '@nestjs/config';
import { UsersService } from '../../users/users.service';

@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy) {
  constructor(
    configService: ConfigService,
    private usersService: UsersService,
  ) {
    super({
      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
      ignoreExpiration: false,
      secretOrKey: configService.get<string>('JWT_SECRET') || 'fallback_secret',
    });
  }

  async validate(payload: any) {
    const user = await this.usersService.findById(payload.sub);
    if (!user) {
      throw new UnauthorizedException('User not found');
    }
    return {
      _id: user._id,
      email: user.email,
      role: user.role,
      fullName: user.fullName,
    };
  }
}

import { Injectable } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { User, UserDocument } from '../users/schemas/user.schema';
import { Order, OrderDocument } from '../orders/schemas/order.schema';
import { UserRole } from '../../common/enums';
import { PaginatedResult, paginate } from '../../common/dto/pagination.dto';

@Injectable()
export class CustomersService {
  constructor(
    @InjectModel(User.name) private userModel: Model<UserDocument>,
    @InjectModel(Order.name) private orderModel: Model<OrderDocument>,
  ) {}

  async findAll(
    page = 1,
    limit = 10,
    search?: string,
  ): Promise<PaginatedResult<any>> {
    const filter: any = { role: UserRole.CUSTOMER };
    if (search) {
      filter.$or = [
        { fullName: { $regex: search, $options: 'i' } },
        { email: { $regex: search, $options: 'i' } },
        { phone: { $regex: search, $options: 'i' } },
      ];
    }

    const skip = (page - 1) * limit;
    const [users, total] = await Promise.all([
      this.userModel
        .find(filter)
        .select('-password')
        .skip(skip)
        .limit(limit)
        .sort({ createdAt: -1 })
        .exec(),
      this.userModel.countDocuments(filter).exec(),
    ]);

    // Enrich with order stats
    const enriched = await Promise.all(
      users.map(async (user) => {
        const orderStats = await this.orderModel.aggregate([
          { $match: { customer: user._id } },
          {
            $group: {
              _id: null,
              totalOrders: { $sum: 1 },
              totalSpent: { $sum: '$total' },
            },
          },
        ]);
        return {
          ...user.toObject(),
          totalOrders: orderStats[0]?.totalOrders || 0,
          totalSpent: orderStats[0]?.totalSpent || 0,
        };
      }),
    );

    return paginate(enriched, total, page, limit);
  }

  async findById(id: string): Promise<any> {
    const user = await this.userModel.findById(id).select('-password').exec();
    if (!user) return null;

    const orders = await this.orderModel
      .find({ customer: id })
      .sort({ createdAt: -1 })
      .limit(20)
      .exec();

    const orderStats = await this.orderModel.aggregate([
      { $match: { customer: user._id } },
      {
        $group: {
          _id: null,
          totalOrders: { $sum: 1 },
          totalSpent: { $sum: '$total' },
        },
      },
    ]);

    return {
      ...user.toObject(),
      totalOrders: orderStats[0]?.totalOrders || 0,
      totalSpent: orderStats[0]?.totalSpent || 0,
      recentOrders: orders,
    };
  }

  async getNewCustomersCount(days = 30): Promise<number> {
    const date = new Date();
    date.setDate(date.getDate() - days);
    return this.userModel
      .countDocuments({
        role: UserRole.CUSTOMER,
        createdAt: { $gte: date },
      })
      .exec();
  }
}

import {
  IsNotEmpty,
  IsOptional,
  IsNumber,
  IsString,
  IsEnum,
  Min,
} from 'class-validator';
import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { InventoryTransactionType } from '../../../common/enums';

export class InventoryTransactionDto {
  @ApiProperty()
  @IsNotEmpty()
  @IsString()
  product: string;

  @ApiProperty()
  @IsNotEmpty()
  @IsNumber()
  @Min(1)
  quantity: number;

  @ApiPropertyOptional()
  @IsOptional()
  @IsString()
  note?: string;
}

export class AdjustInventoryDto {
  @ApiProperty()
  @IsNotEmpty()
  @IsString()
  product: string;

  @ApiProperty()
  @IsNotEmpty()
  @IsNumber()
  quantity: number;

  @ApiPropertyOptional()
  @IsOptional()
  @IsString()
  note?: string;
}

import {
  Controller,
  Get,
  Post,
  Body,
  Query,
  UseGuards,
  Request,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { ApiBearerAuth, ApiTags, ApiOperation } from '@nestjs/swagger';
import { InventoryService } from './inventory.service';
import {
  InventoryTransactionDto,
  AdjustInventoryDto,
} from './dto/inventory.dto';
import { Roles } from '../../common/decorators/roles.decorator';
import { RolesGuard } from '../../common/guards/roles.guard';

@ApiTags('inventory')
@Controller('inventory')
@UseGuards(AuthGuard('jwt'), RolesGuard)
@Roles('ADMIN', 'STAFF')
@ApiBearerAuth()
export class InventoryController {
  constructor(private inventoryService: InventoryService) {}

  @Get()
  @ApiOperation({ summary: 'Get all inventory' })
  findAll() {
    return this.inventoryService.findAll();
  }

  @Get('low-stock')
  @ApiOperation({ summary: 'Get low stock items' })
  getLowStock() {
    return this.inventoryService.getLowStock();
  }

  @Get('transactions')
  @ApiOperation({ summary: 'Get inventory transactions' })
  getTransactions(@Query('productId') productId?: string) {
    return this.inventoryService.getTransactions(productId);
  }

  @Post('import')
  @ApiOperation({ summary: 'Import stock' })
  importStock(@Body() dto: InventoryTransactionDto, @Request() req: any) {
    return this.inventoryService.importStock(dto, req.user._id);
  }

  @Post('export')
  @ApiOperation({ summary: 'Export stock' })
  exportStock(@Body() dto: InventoryTransactionDto, @Request() req: any) {
    return this.inventoryService.exportStock(dto, req.user._id);
  }

  @Post('adjust')
  @ApiOperation({ summary: 'Adjust stock' })
  adjustStock(@Body() dto: AdjustInventoryDto, @Request() req: any) {
    return this.inventoryService.adjustStock(dto, req.user._id);
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Types } from 'mongoose';
import {
  Inventory,
  InventoryDocument,
  InventoryTransaction,
  InventoryTransactionDocument,
} from './schemas/inventory.schema';
import {
  InventoryTransactionDto,
  AdjustInventoryDto,
} from './dto/inventory.dto';
import { ProductsService } from '../products/products.service';
import { InventoryStatus, InventoryTransactionType } from '../../common/enums';

@Injectable()
export class InventoryService {
  constructor(
    @InjectModel(Inventory.name)
    private inventoryModel: Model<InventoryDocument>,
    @InjectModel(InventoryTransaction.name)
    private transactionModel: Model<InventoryTransactionDocument>,
    private productsService: ProductsService,
  ) {}

  private getStatus(currentStock: number, minStock: number): InventoryStatus {
    if (currentStock <= 0) return InventoryStatus.OUT_OF_STOCK;
    if (currentStock <= minStock) return InventoryStatus.LOW_STOCK;
    return InventoryStatus.IN_STOCK;
  }

  async findAll(): Promise<InventoryDocument[]> {
    try {
      const productModel = this.inventoryModel.db.model('Product');
      const products = await productModel.find({ isDeleted: false }).exec();

      const existingInventories = await this.inventoryModel.find().exec();
      const existingProductIds = new Set(
        existingInventories.map((inv) => inv.product.toString()),
      );

      const missingProducts = products.filter(
        (p) => !existingProductIds.has(p._id.toString()),
      );

      if (missingProducts.length > 0) {
        const newInventories = missingProducts.map((p) => {
          const currentStock = p.stock || 0;
          let status = InventoryStatus.IN_STOCK;
          if (currentStock <= 0) {
            status = InventoryStatus.OUT_OF_STOCK;
          } else if (currentStock <= 10) {
            status = InventoryStatus.LOW_STOCK;
          }
          return {
            product: p._id,
            currentStock,
            minStock: 10,
            maxStock: 1000,
            status,
            lastUpdated: new Date(),
          };
        });
        await this.inventoryModel.insertMany(newInventories);
      }
    } catch (err) {
      console.error('Failed to sync missing product inventory records:', err);
    }
    const items = await this.inventoryModel
      .find()
      .populate('product', 'name sku images price')
      .exec();
    return items.filter((item) => item.product !== null);
  }

  async getLowStock(): Promise<InventoryDocument[]> {
    return this.inventoryModel
      .find({
        $or: [
          { status: InventoryStatus.LOW_STOCK },
          { status: InventoryStatus.OUT_OF_STOCK },
        ],
      })
      .populate('product', 'name sku images price')
      .exec();
  }

  async importStock(
    dto: InventoryTransactionDto,
    userId?: string,
  ): Promise<InventoryDocument> {
    const productObjectId = new Types.ObjectId(dto.product);
    let inventory = await this.inventoryModel
      .findOne({ product: productObjectId })
      .exec();

    if (!inventory) {
      inventory = new this.inventoryModel({
        product: productObjectId,
        currentStock: dto.quantity,
      });
    } else {
      inventory.currentStock += dto.quantity;
    }

    inventory.status = this.getStatus(
      inventory.currentStock,
      inventory.minStock,
    );
    inventory.lastUpdated = new Date();
    await inventory.save();

    // Set product stock to match inventory currentStock
    await this.productsService.setStock(
      dto.product.toString(),
      inventory.currentStock,
    );

    // Log transaction
    await this.transactionModel.create({
      product: productObjectId,
      type: InventoryTransactionType.IMPORT,
      quantity: dto.quantity,
      note: dto.note,
      createdBy: userId,
    });

    return inventory;
  }

  async exportStock(
    dto: InventoryTransactionDto,
    userId?: string,
  ): Promise<InventoryDocument> {
    const productObjectId = new Types.ObjectId(dto.product);
    const inventory = await this.inventoryModel
      .findOne({ product: productObjectId })
      .exec();
    if (!inventory) throw new NotFoundException('Inventory record not found');

    inventory.currentStock = Math.max(0, inventory.currentStock - dto.quantity);
    inventory.status = this.getStatus(
      inventory.currentStock,
      inventory.minStock,
    );
    inventory.lastUpdated = new Date();
    await inventory.save();

    // Set product stock to match inventory currentStock
    await this.productsService.setStock(
      dto.product.toString(),
      inventory.currentStock,
    );

    await this.transactionModel.create({
      product: productObjectId,
      type: InventoryTransactionType.EXPORT,
      quantity: dto.quantity,
      note: dto.note,
      createdBy: userId,
    });

    return inventory;
  }

  async adjustStock(
    dto: AdjustInventoryDto,
    userId?: string,
  ): Promise<InventoryDocument> {
    const productObjectId = new Types.ObjectId(dto.product);
    let inventory = await this.inventoryModel
      .findOne({ product: productObjectId })
      .exec();

    if (!inventory) {
      inventory = new this.inventoryModel({
        product: productObjectId,
        currentStock: dto.quantity,
      });
    } else {
      inventory.currentStock = dto.quantity;
    }

    inventory.status = this.getStatus(
      inventory.currentStock,
      inventory.minStock,
    );
    inventory.lastUpdated = new Date();
    await inventory.save();

    // Set product stock to match inventory currentStock
    await this.productsService.setStock(
      dto.product.toString(),
      inventory.currentStock,
    );

    await this.transactionModel.create({
      product: productObjectId,
      type: InventoryTransactionType.ADJUST,
      quantity: dto.quantity,
      note: dto.note,
      createdBy: userId,
    });

    return inventory;
  }

  async getTransactions(
    productId?: string,
  ): Promise<InventoryTransactionDocument[]> {
    const filter: any = {};
    if (productId) filter.product = productId;
    return this.transactionModel
      .find(filter)
      .populate('product', 'name sku')
      .populate('createdBy', 'fullName')
      .sort({ createdAt: -1 })
      .limit(50)
      .exec();
  }

  async getLowStockCount(): Promise<number> {
    return this.inventoryModel
      .countDocuments({
        $or: [
          { status: InventoryStatus.LOW_STOCK },
          { status: InventoryStatus.OUT_OF_STOCK },
        ],
      })
      .exec();
  }
}

import {
  Injectable,
  NotFoundException,
  BadRequestException,
  Logger,
} from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import {
  LandingPage,
  LandingPageDocument,
} from './schemas/landing-page.schema';
import {
  CreateLandingPageDto,
  GenerateLandingPageDto,
  SubmitOrderDto,
} from './dto/landing-page.dto';
import { Order, OrderDocument } from '../orders/schemas/order.schema';
import { OrderStatus, PaymentMethod, PaymentStatus } from '../../common/enums';
import { ConfigService } from '@nestjs/config';
import { OrdersService } from '../orders/orders.service';

@Injectable()
export class LandingPageService {
  private readonly logger = new Logger(LandingPageService.name);

  constructor(
    @InjectModel(LandingPage.name)
    private landingPageModel: Model<LandingPageDocument>,
    @InjectModel(Order.name) private orderModel: Model<OrderDocument>,
    private ordersService: OrdersService,
    private configService: ConfigService,
  ) {}

  async findAll(): Promise<LandingPageDocument[]> {
    return this.landingPageModel.find().sort({ createdAt: -1 }).exec();
  }

  async findBySlug(slug: string): Promise<LandingPageDocument> {
    const page = await this.landingPageModel
      .findOne({ slug, status: true })
      .exec();
    if (!page) {
      throw new NotFoundException('Không tìm thấy trang bán hàng');
    }
    return page;
  }

  async findOne(id: string): Promise<LandingPageDocument> {
    const page = await this.landingPageModel.findById(id).exec();
    if (!page) {
      throw new NotFoundException('Không tìm thấy trang bán hàng');
    }
    return page;
  }

  async create(dto: CreateLandingPageDto): Promise<LandingPageDocument> {
    const existing = await this.landingPageModel
      .findOne({ slug: dto.slug })
      .exec();
    if (existing) {
      throw new BadRequestException('Đường dẫn (slug) đã được sử dụng');
    }
    return this.landingPageModel.create(dto);
  }

  async update(
    id: string,
    dto: CreateLandingPageDto,
  ): Promise<LandingPageDocument> {
    const existing = await this.landingPageModel
      .findOne({ slug: dto.slug, _id: { $ne: id } })
      .exec();
    if (existing) {
      throw new BadRequestException(
        'Đường dẫn (slug) đã được sử dụng bởi trang khác',
      );
    }
    const page = await this.landingPageModel
      .findByIdAndUpdate(id, dto, { new: true })
      .exec();
    if (!page) {
      throw new NotFoundException('Không tìm thấy trang bán hàng');
    }
    return page;
  }

  async remove(id: string): Promise<{ message: string }> {
    const result = await this.landingPageModel.findByIdAndDelete(id).exec();
    if (!result) {
      throw new NotFoundException('Không tìm thấy trang bán hàng');
    }
    return { message: 'Xóa trang bán hàng thành công' };
  }

  async submitOrder(dto: SubmitOrderDto): Promise<OrderDocument> {
    const page = await this.landingPageModel.findById(dto.landingPageId).exec();
    if (!page) {
      throw new NotFoundException('Không tìm thấy trang bán hàng');
    }

    // Find selected package details
    const selectedPkg = page.packages.find((p) => p.name === dto.packageName);
    const orderPrice = selectedPkg ? selectedPkg.price : page.price;

    const randomSuffix = Math.floor(1000 + Math.random() * 9000);
    const orderCode = `LP${new Date().toISOString().slice(2, 10).replace(/-/g, '')}${randomSuffix}`;

    // Create a new order integrated directly with main order system
    const newOrder = new this.orderModel({
      orderCode,
      customer: null, // Guest checkout
      customerName: dto.fullName,
      customerEmail: `${dto.phone}@truongthanh.vn`, // Dummy email
      phone: dto.phone,
      shippingAddress: dto.address,
      note: dto.note ? `${dto.packageName} - ${dto.note}` : dto.packageName,
      items: [
        {
          product: null,
          name: `${page.title} (${dto.packageName})`,
          price: orderPrice,
          quantity: 1,
          image: page.images?.[0] || '',
        },
      ],
      paymentMethod: PaymentMethod.COD,
      paymentStatus: PaymentStatus.UNPAID,
      orderStatus: OrderStatus.PENDING,
      subtotal: orderPrice,
      shippingFee: 0,
      discount: 0,
      total: orderPrice,
    });

    const savedOrder = await newOrder.save();

    // Sync to Google Sheet (async)
    this.ordersService
      .syncToGoogleSheet(savedOrder)
      .catch((err) => this.logger.error(err));

    return savedOrder;
  }

  async generateLandingPage(dto: GenerateLandingPageDto): Promise<any> {
    const apiKey = this.configService.get<string>('GEMINI_API_KEY');
    if (!apiKey) {
      this.logger.warn(
        'GEMINI_API_KEY not configured. Using fallback template.',
      );
      return this.generateFallbackTemplate(dto);
    }

    this.logger.log(
      `Calling Gemini AI for landing page generation: ${dto.title}`,
    );

    // Gemini API via Google AI Studio (không cần Google Cloud Console)
    const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${apiKey}`;

    const promptText = `
Bạn là chuyên gia thiết kế và lập trình viên landing page bán hàng chuyên nghiệp, có tỷ lệ chuyển đổi (CR) cực kỳ cao.
Hãy tạo nội dung landing page cho sản phẩm sau:
Tiêu đề: "${dto.title}"
Giá bán khuyến mãi: ${dto.price} VNĐ
Giá gốc: ${dto.originalPrice || dto.price * 1.5} VNĐ
Yêu cầu bổ sung của khách hàng: "${dto.prompt || 'Hãy tối ưu giao diện bán hàng chuyên nghiệp'}"

