  authorName: string;

  @Prop()
  avatar: string;

  @Prop({ required: true })
  content: string;

  @Prop({ default: 5 })
  rating: number;
}

@Schema({ timestamps: true })
export class LandingPage {
  @Prop({ required: true })
  title: string;

  @Prop({ required: true, unique: true })
